import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function px(n) {
  return n * GRID;
}

function islandAt(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function buildAdjacency(islands) {
  const byRow = new Map();
  const byCol = new Map();

  for (const i of islands) {
    if (!byRow.has(i.y)) byRow.set(i.y, []);
    if (!byCol.has(i.x)) byCol.set(i.x, []);
    byRow.get(i.y).push(i);
    byCol.get(i.x).push(i);
  }

  for (const arr of byRow.values()) arr.sort((a, b) => a.x - b.x);
  for (const arr of byCol.values()) arr.sort((a, b) => a.y - b.y);

  const neighbors = new Map();
  for (const i of islands) neighbors.set(i.id, []);

  for (const arr of byRow.values()) {
    for (let k = 0; k < arr.length; k++) {
      if (k > 0) neighbors.get(arr[k].id).push(arr[k - 1].id);
      if (k < arr.length - 1) neighbors.get(arr[k].id).push(arr[k + 1].id);
    }
  }

  for (const arr of byCol.values()) {
    for (let k = 0; k < arr.length; k++) {
      if (k > 0) neighbors.get(arr[k].id).push(arr[k - 1].id);
      if (k < arr.length - 1) neighbors.get(arr[k].id).push(arr[k + 1].id);
    }
  }

  return neighbors;
}

function moveCursor(islands, neighbors, cursorId, dir) {
  const cur = islandAt(islands, cursorId);
  if (!cur) return cursorId;

  const candIds = neighbors.get(cur.id) ?? [];
  let best = null;

  for (const id of candIds) {
    const i = islandAt(islands, id);
    if (!i) continue;

    if (dir === 'ArrowLeft' && i.y === cur.y && i.x < cur.x) {
      if (!best || i.x > best.x) best = i;
    }
    if (dir === 'ArrowRight' && i.y === cur.y && i.x > cur.x) {
      if (!best || i.x < best.x) best = i;
    }
    if (dir === 'ArrowUp' && i.x === cur.x && i.y < cur.y) {
      if (!best || i.y > best.y) best = i;
    }
    if (dir === 'ArrowDown' && i.x === cur.x && i.y > cur.y) {
      if (!best || i.y < best.y) best = i;
    }
  }

  return best ? best.id : cursorId;
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = puzzles[puzzleIndex];

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [keySelectId, setKeySelectId] = useState(null);
  const [error, setError] = useState(null);

  const islands = puzzle.islands;
  const neighbors = useMemo(() => buildAdjacency(islands), [islands]);

  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  // Refs for key handler so it works even when window blur/focus changes.
  const stateRef = useRef(null);
  stateRef.current = {
    islands,
    neighbors,
    bridges,
    cursorId,
    keySelectId,
  };

  function fullResetToPuzzle(nextIndex) {
    setPuzzleIndex(nextIndex);
    setBridges(new Map());
    setSelectedId(null);
    setKeySelectId(null);
    setError(null);
    setCursorId(0);
  }

  function clearErrorOnValidMove() {
    setError(null);
  }

  function trySetBridge(fromId, toId, mode) {
    // mode: 'cycle' (none->1->2->0), 'remove'
    const from = islandAt(islands, fromId);
    const to = islandAt(islands, toId);
    if (!from || !to) return;

    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;

    let next = current;
    if (mode === 'remove') next = 0;
    if (mode === 'cycle') next = current === 0 ? 1 : current === 1 ? 2 : 0;

    const delta = next - current;

    // If cycling to 0, always allow.
    if (delta > 0) {
      const { valid, error: err } = canAddBridge(islands, bridges, from, to, +1);
      if (!valid) {
        setError(err);
        return;
      }
      if (delta === 2) {
        // would only happen if current=0 and next=2 (we don't do that)
      }
    }

    if (delta === 1) {
      // add one bridge
      setBridges((prev) => {
        const copy = new Map(prev);
        copy.set(key, (copy.get(key) ?? 0) + 1);
        return copy;
      });
      clearErrorOnValidMove();
      setCursorId(0);
      return;
    }

    if (delta === -1) {
      // remove one bridge
      setBridges((prev) => {
        const copy = new Map(prev);
        const n = (copy.get(key) ?? 0) - 1;
        if (n <= 0) copy.delete(key);
        else copy.set(key, n);
        return copy;
      });
      clearErrorOnValidMove();
      setCursorId(0);
      return;
    }

    if (delta === -2 || next === 0) {
      // remove entirely
      setBridges((prev) => {
        const copy = new Map(prev);
        copy.delete(key);
        return copy;
      });
      clearErrorOnValidMove();
      setCursorId(0);
      return;
    }

    // No-op still clears selection
    clearErrorOnValidMove();
    setCursorId(0);
  }

  function onIslandClick(id, e) {
    e.preventDefault();

    // Ctrl+click removes bridge between selected and this, only if exists.
    if (e.ctrlKey && selectedId != null && selectedId !== id) {
      trySetBridge(selectedId, id, 'remove');
      setSelectedId(null);
      return;
    }

    if (selectedId == null) {
      setSelectedId(id);
      return;
    }

    if (selectedId === id) {
      setSelectedId(null);
      return;
    }

    trySetBridge(selectedId, id, 'cycle');
    setSelectedId(null);
  }

  function onBridgeContextMenu(from, to, e) {
    e.preventDefault();
    trySetBridge(from.id, to.id, 'remove');
    setSelectedId(null);
    setKeySelectId(null);
  }

  function onBridgeClick(from, to, e) {
    if (e.ctrlKey) {
      e.preventDefault();
      trySetBridge(from.id, to.id, 'remove');
      setSelectedId(null);
      setKeySelectId(null);
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      const s = stateRef.current;
      if (!s) return;

      const { islands, neighbors, bridges } = s;

      if (e.key === 'Escape') {
        setKeySelectId(null);
        setSelectedId(null);
        return;
      }

      if (
        e.key === 'ArrowLeft' ||
        e.key === 'ArrowRight' ||
        e.key === 'ArrowUp' ||
        e.key === 'ArrowDown'
      ) {
        e.preventDefault();
        setCursorId((cur) => moveCursor(islands, neighbors, cur, e.key));
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        setSelectedId(null); // mouse selection cleared when using keyboard

        setKeySelectId((sel) => {
          if (sel == null) {
            return s.cursorId;
          }
          if (sel === s.cursorId) {
            return null;
          }

          const from = islandAt(islands, sel);
          const to = islandAt(islands, s.cursorId);
          if (!from || !to) return null;

          const key = canonicalBridgeKey(from, to);
          const current = bridges.get(key) ?? 0;
          const next = current === 0 ? 1 : current === 1 ? 2 : 0;
          const delta = next - current;

          if (delta > 0) {
            const { valid, error: err } = canAddBridge(islands, bridges, from, to, +1);
            if (!valid) {
              setError(err);
              return null;
            }
          }

          // Apply update
          if (next === 0) {
            setBridges((prev) => {
              const copy = new Map(prev);
              copy.delete(key);
              return copy;
            });
          } else {
            setBridges((prev) => {
              const copy = new Map(prev);
              copy.set(key, next);
              return copy;
            });
          }

          setError(null);
          setCursorId(0);
          return null;
        });
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);

  const bridgeSegments = useMemo(() => {
    const segs = [];
    for (const [key, n] of bridges.entries()) {
      if (!n) continue;
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const a = islands.find((i) => i.x === x1 && i.y === y1);
      const b = islands.find((i) => i.x === x2 && i.y === y2);
      if (!a || !b) continue;
      segs.push({ a, b, n, key });
    }
    return segs;
  }, [bridges, islands]);

  return (
    <div>
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => fullResetToPuzzle(Number(e.target.value))}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>
        <button onClick={() => fullResetToPuzzle(puzzleIndex)}>Reset</button>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        className="board"
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Bridges */}
        {bridgeSegments.flatMap(({ a, b, n, key }) => {
          const ax = px(a.x);
          const ay = px(a.y);
          const bx = px(b.x);
          const by = px(b.y);

          const horizontal = ay === by;
          const offset = 4;
          const lines = [];

          const commonProps = {
            key: `${key}-1`,
            className: 'bridge',
            onContextMenu: (e) => onBridgeContextMenu(a, b, e),
            onClick: (e) => onBridgeClick(a, b, e),
          };

          if (n === 1) {
            lines.push(
              <line {...commonProps} x1={ax} y1={ay} x2={bx} y2={by} />
            );
          } else if (n === 2) {
            if (horizontal) {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-a`}
                  x1={ax}
                  y1={ay - offset}
                  x2={bx}
                  y2={by - offset}
                />
              );
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-b`}
                  x1={ax}
                  y1={ay + offset}
                  x2={bx}
                  y2={by + offset}
                />
              );
            } else {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-a`}
                  x1={ax - offset}
                  y1={ay}
                  x2={bx - offset}
                  y2={by}
