import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function px(n) {
  return n * GRID;
}

function islandAt(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function buildAdjacency(islands) {
  const byRow = new Map();
  const byCol = new Map();

  for (const i of islands) {
    if (!byRow.has(i.y)) byRow.set(i.y, []);
    if (!byCol.has(i.x)) byCol.set(i.x, []);
    byRow.get(i.y).push(i);
    byCol.get(i.x).push(i);
  }

  for (const arr of byRow.values()) arr.sort((a, b) => a.x - b.x);
  for (const arr of byCol.values()) arr.sort((a, b) => a.y - b.y);

  const neighbors = new Map();
  for (const i of islands) neighbors.set(i.id, []);

  for (const arr of byRow.values()) {
    for (let k = 0; k < arr.length; k++) {
      if (k > 0) neighbors.get(arr[k].id).push(arr[k - 1].id);
      if (k < arr.length - 1) neighbors.get(arr[k].id).push(arr[k + 1].id);
    }
  }

  for (const arr of byCol.values()) {
    for (let k = 0; k < arr.length; k++) {
      if (k > 0) neighbors.get(arr[k].id).push(arr[k - 1].id);
      if (k < arr.length - 1) neighbors.get(arr[k].id).push(arr[k + 1].id);
    }
  }

  return neighbors;
}

function moveCursor(islands, neighbors, cursorId, dir) {
  const cur = islandAt(islands, cursorId);
  if (!cur) return cursorId;

  const candIds = neighbors.get(cur.id) ?? [];
  let best = null;

  for (const id of candIds) {
    const i = islandAt(islands, id);
    if (!i) continue;

    if (dir === 'ArrowLeft' && i.y === cur.y && i.x < cur.x) {
      if (!best || i.x > best.x) best = i;
    }
    if (dir === 'ArrowRight' && i.y === cur.y && i.x > cur.x) {
      if (!best || i.x < best.x) best = i;
    }
    if (dir === 'ArrowUp' && i.x === cur.x && i.y < cur.y) {
      if (!best || i.y > best.y) best = i;
    }
    if (dir === 'ArrowDown' && i.x === cur.x && i.y > cur.y) {
      if (!best || i.y < best.y) best = i;
    }
  }

  return best ? best.id : cursorId;
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = puzzles[puzzleIndex];

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [keySelectId, setKeySelectId] = useState(null);
  const [error, setError] = useState(null);

  const islands = puzzle.islands;
  const neighbors = useMemo(() => buildAdjacency(islands), [islands]);

  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

