        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Bridges */}
        {bridgeSegments.flatMap(({ a, b, n, key }) => {
          const ax = px(a.x);
          const ay = px(a.y);
          const bx = px(b.x);
          const by = px(b.y);

          const horizontal = ay === by;
          const offset = 4;
          const lines = [];

          const commonProps = {
            key: `${key}-1`,
            className: 'bridge',
            onContextMenu: (e) => onBridgeContextMenu(a, b, e),
            onClick: (e) => onBridgeClick(a, b, e),
          };

          if (n === 1) {
            lines.push(
              <line {...commonProps} x1={ax} y1={ay} x2={bx} y2={by} />
            );
          } else if (n === 2) {
            if (horizontal) {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-a`}
                  x1={ax}
                  y1={ay - offset}
                  x2={bx}
                  y2={by - offset}
                />
              );
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-b`}
                  x1={ax}
                  y1={ay + offset}
                  x2={bx}
                  y2={by + offset}
                />
              );
            } else {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-a`}
                  x1={ax - offset}
                  y1={ay}
                  x2={bx - offset}
                  y2={by}
                />
              );
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-b`}
                  x1={ax + offset}
                  y1={ay}
                  x2={bx + offset}
                  y2={by}
                />
              );
            }
          }
          return lines;
        })}

        {/* Cursor (not a circle) */}
        {(() => {
          const c = islandAt(islands, cursorId);
          if (!c) return null;
          const x = px(c.x);
          const y = px(c.y);
          const size = 34;
          return (
            <rect
              className="cursor"
              x={x - size / 2}
              y={y - size / 2}
              width={size}
              height={size}
            />
          );
        })()}

        {/* Islands */}
        {islands.map((i) => {
          const x = px(i.x);
          const y = px(i.y);
          const isMouseSelected = selectedId === i.id;
          const isKeySelected = keySelectId === i.id;
          const cur = counts.get(i.id) ?? 0;
          const over = cur > i.value;

          return (
            <g
              key={i.id}
              className="island"
              onClick={(e) => onIslandClick(i.id, e)}
            >
              <circle
                cx={x}
                cy={y}
                r={16}
                className={
                  'island-circle' +
                  (isMouseSelected || isKeySelected ? ' island-selected' : '') +
                  (over ? ' island-over' : '')
                }
              />
              <text x={x} y={y + 5} textAnchor="middle" className="island-text">
                {i.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
