      setSelectedId(id);
      return;
    }

    if (selectedId === id) {
      setSelectedId(null);
      return;
    }

    trySetBridge(selectedId, id, 'cycle');
    setSelectedId(null);
  }

  function onBridgeContextMenu(from, to, e) {
    e.preventDefault();
    trySetBridge(from.id, to.id, 'remove');
    setSelectedId(null);
    setKeySelectId(null);
  }

  function onBridgeClick(from, to, e) {
    if (e.ctrlKey) {
      e.preventDefault();
      trySetBridge(from.id, to.id, 'remove');
      setSelectedId(null);
      setKeySelectId(null);
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      const s = stateRef.current;
      if (!s) return;

      const { islands, neighbors, bridges } = s;

      if (e.key === 'Escape') {
        setKeySelectId(null);
        setSelectedId(null);
        return;
      }

      if (
        e.key === 'ArrowLeft' ||
        e.key === 'ArrowRight' ||
        e.key === 'ArrowUp' ||
        e.key === 'ArrowDown'
      ) {
        e.preventDefault();
        setCursorId((cur) => moveCursor(islands, neighbors, cur, e.key));
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        setSelectedId(null); // mouse selection cleared when using keyboard

        setKeySelectId((sel) => {
          if (sel == null) {
            return s.cursorId;
          }
          if (sel === s.cursorId) {
            return null;
          }

          const from = islandAt(islands, sel);
          const to = islandAt(islands, s.cursorId);
          if (!from || !to) return null;

          const key = canonicalBridgeKey(from, to);
          const current = bridges.get(key) ?? 0;
          const next = current === 0 ? 1 : current === 1 ? 2 : 0;
          const delta = next - current;

          if (delta > 0) {
            const { valid, error: err } = canAddBridge(islands, bridges, from, to, +1);
            if (!valid) {
              setError(err);
              return null;
            }
          }

          // Apply update
          if (next === 0) {
            setBridges((prev) => {
              const copy = new Map(prev);
              copy.delete(key);
              return copy;
            });
          } else {
            setBridges((prev) => {
              const copy = new Map(prev);
              copy.set(key, next);
              return copy;
            });
          }

          setError(null);
          setCursorId(0);
          return null;
        });
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);

  const bridgeSegments = useMemo(() => {
    const segs = [];
    for (const [key, n] of bridges.entries()) {
      if (!n) continue;
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const a = islands.find((i) => i.x === x1 && i.y === y1);
      const b = islands.find((i) => i.x === x2 && i.y === y2);
      if (!a || !b) continue;
      segs.push({ a, b, n, key });
    }
    return segs;
  }, [bridges, islands]);

  return (
    <div>
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => fullResetToPuzzle(Number(e.target.value))}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>
        <button onClick={() => fullResetToPuzzle(puzzleIndex)}>Reset</button>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        className="board"
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Bridges */}
        {bridgeSegments.flatMap(({ a, b, n, key }) => {
          const ax = px(a.x);
          const ay = px(a.y);
          const bx = px(b.x);
          const by = px(b.y);

          const horizontal = ay === by;
          const offset = 4;
          const lines = [];

          const commonProps = {
            key: `${key}-1`,
            className: 'bridge',
            onContextMenu: (e) => onBridgeContextMenu(a, b, e),
            onClick: (e) => onBridgeClick(a, b, e),
          };

          if (n === 1) {
            lines.push(
              <line {...commonProps} x1={ax} y1={ay} x2={bx} y2={by} />
            );
          } else if (n === 2) {
            if (horizontal) {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-a`}
                  x1={ax}
                  y1={ay - offset}
                  x2={bx}
                  y2={by - offset}
                />
              );
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-b`}
                  x1={ax}
                  y1={ay + offset}
                  x2={bx}
                  y2={by + offset}
                />
              );
            } else {
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-a`}
                  x1={ax - offset}
                  y1={ay}
                  x2={bx - offset}
                  y2={by}
                />
              );
              lines.push(
                <line
                  {...commonProps}
                  key={`${key}-b`}
                  x1={ax + offset}
                  y1={ay}
                  x2={bx + offset}
                  y2={by}
                />
              );
            }
          }
          return lines;
        })}

        {/* Cursor (not a circle) */}
        {(() => {
          const c = islandAt(islands, cursorId);
          if (!c) return null;
          const x = px(c.x);
          const y = px(c.y);
          const size = 34;
          return (
            <rect
              className="cursor"
              x={x - size / 2}
              y={y - size / 2}
              width={size}
              height={size}
            />
          );
        })()}

        {/* Islands */}
        {islands.map((i) => {
          const x = px(i.x);
          const y = px(i.y);
          const isMouseSelected = selectedId === i.id;
          const isKeySelected = keySelectId === i.id;
          const cur = counts.get(i.id) ?? 0;
          const over = cur > i.value;

          return (
            <g
              key={i.id}
              className="island"
              onClick={(e) => onIslandClick(i.id, e)}
            >
              <circle
                cx={x}
                cy={y}
                r={16}
                className={
                  'island-circle' +
                  (isMouseSelected || isKeySelected ? ' island-selected' : '') +
                  (over ? ' island-over' : '')
                }
              />
              <text x={x} y={y + 5} textAnchor="middle" className="island-text">
                {i.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
